"use client";

import { ReactNode } from "react";
import {
  LiveblocksProvider,
  RoomProvider,
  ClientSideSuspense,
} from "@liveblocks/react/suspense";

export function Room({ children }: { children: ReactNode }) {
  const roomId = `like-button-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;
  const publicApiKey = process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!;

  return (
    <LiveblocksProvider publicApiKey={publicApiKey}>
      <RoomProvider id={roomId} initialStorage={{ likes: 0 }}>
        <ClientSideSuspense fallback={<div>Loading...</div>}>
          {children}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import { useStorage, useMutation } from "@liveblocks/react/suspense";

export function LikeButton() {
  const likes = useStorage((root: any) => root.likes);

  const increment = useMutation(({ storage }) => {
    const currentLikes = (storage.get("likes") as number) ?? 0;
    storage.set("likes", currentLikes + 1);
  }, []);

  return (
    <div>
      <button id="like-button" onClick={() => increment()}>
        Like
      </button>
      <span id="like-count">{likes}</span>
    </div>
  );
}

import { Room } from "./Room";
import { LikeButton } from "./LikeButton";

export default function Page() {
  return (
    <Room>
      <main>
        <h1>Collaborative Like Button</h1>
        <LikeButton />
      </main>
    </Room>
  );
}

